class Solution:
    def averageOfSubtree(self, root):
        nodes = []
        def collect(node):
            if not node:
                return
            nodes.append(node)
            collect(node.left)
            collect(node.right)
        collect(root)
        def subtree_vals(node):
            if not node:
                return []
            return [node.val] + subtree_vals(node.left) + subtree_vals(node.right)
        count = 0
        for nd in nodes:
            vals = subtree_vals(nd)
            if nd.val == sum(vals) // len(vals):
                count += 1
        return count

