class Solution:
    def averageOfSubtree(self, root):
        self.count = 0
        def walk(node):
            if not node:
                return (0, 0)
            ls, lc = walk(node.left)
            rs, rc = walk(node.right)
            s = ls + rs + node.val
            c = lc + rc + 1
            if node.val == s // c:
                self.count += 1
            return (s, c)
        walk(root)
        return self.count

