var averageOfSubtree = function(root) {
    let count = 0;
    function walk(node) {
        if (!node) return [0, 0];
        const [ls, lc] = walk(node.left);
        const [rs, rc] = walk(node.right);
        const s = ls + rs + node.val;
        const c = lc + rc + 1;
        if (node.val === Math.floor(s / c)) count++;
        return [s, c];
    }
    walk(root);
    return count;
};
